"use client";

import { useState } from "react";
import Link from "next/link";

import { apiFetch } from "@/lib/api";
import { cn } from "@/lib/utils";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { useToast } from "@/hooks/use-toast";

/* -- types --------------------------------------------------------- */

interface Template {
  id: string;
  name: string;
  description: string;
  category: string;
  severity: string;
  icon: string;
  features: string[];
}

/* -- template data -------------------------------------------------- */

const TEMPLATES: Template[] = [
  {
    id: "cert-monitor",
    name: "Certificate Monitor",
    description:
      "Monitor SSL/TLS certificates for expiration, chain validity, and configuration issues. Get alerted before certificates expire.",
    category: "certificate",
    severity: "high",
    icon: "[CERT]",
    features: [
      "Certificate expiry warnings (30d, 14d, 7d, 1d)",
      "Chain validation monitoring",
      "Certificate transparency log tracking",
      "SANs change detection",
      "Weak algorithm alerts",
    ],
  },
  {
    id: "tls-security",
    name: "TLS Security",
    description:
      "Continuously audit TLS configuration for security weaknesses including deprecated protocols, weak ciphers, and misconfigurations.",
    category: "tls",
    severity: "high",
    icon: "[TLS]",
    features: [
      "Deprecated protocol detection (SSLv3, TLS 1.0/1.1)",
      "Weak cipher suite identification",
      "Perfect forward secrecy verification",
      "HSTS header enforcement check",
      "Protocol downgrade attack detection",
    ],
  },
  {
    id: "dns-change",
    name: "DNS Change Monitor",
    description:
      "Track DNS record changes across all record types. Detect unauthorized modifications and potential DNS hijacking attempts.",
    category: "dns",
    severity: "critical",
    icon: "[DNS]",
    features: [
      "A/AAAA record change detection",
      "MX record monitoring",
      "NS record change alerts",
      "SPF/DKIM/DMARC validation",
      "DNS propagation tracking",
    ],
  },
  {
    id: "host-uptime",
    name: "Host Uptime",
    description:
      "Monitor host availability with configurable probe intervals. Track response times and detect outages in real time.",
    category: "availability",
    severity: "critical",
    icon: "[UP]",
    features: [
      "HTTP/HTTPS endpoint monitoring",
      "Configurable check intervals",
      "Response time tracking",
      "Status code validation",
      "Downtime duration reporting",
    ],
  },
  {
    id: "full-audit",
    name: "Full Infrastructure Audit",
    description:
      "Comprehensive security audit combining certificate, TLS, DNS, headers, and infrastructure checks in a single detection.",
    category: "comprehensive",
    severity: "medium",
    icon: "[***]",
    features: [
      "Complete certificate analysis",
      "TLS configuration audit",
      "DNS record baseline monitoring",
      "HTTP security headers check",
      "Open port scanning",
      "WHOIS change detection",
      "Cloud provider identification",
    ],
  },
];

const severityColor: Record<string, string> = {
  critical: "text-destructive",
  high: "text-warning",
  medium: "text-primary",
  low: "text-muted-foreground",
};

const categoryColor: Record<string, string> = {
  certificate: "text-warning",
  tls: "text-primary",
  dns: "text-destructive",
  availability: "text-destructive",
  comprehensive: "text-primary",
};

/* -- page ----------------------------------------------------------- */

export default function InfraTemplatesPage() {
  const [enableLoading, setEnableLoading] = useState<Record<string, boolean>>(
    {},
  );
  const [enabledTemplates, setEnabledTemplates] = useState<Set<string>>(
    new Set(),
  );
  const { toast } = useToast();

  async function enableTemplate(template: Template) {
    setEnableLoading((prev) => ({ ...prev, [template.id]: true }));
    try {
      await apiFetch<{ data: { id: string } }>("/api/detections/from-template", {
        method: "POST",
        credentials: "include",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          templateId: template.id,
          moduleId: "infra",
        }),
      });
      setEnabledTemplates((prev) => {
        const next = new Set(prev);
        next.add(template.id);
        return next;
      });
      toast(
        `Detection "${template.name}" created and enabled. View it in detections.`,
      );
    } catch (err) {
      toast(
        err instanceof Error
          ? `Failed: ${err.message}`
          : "Failed to enable template",
      );
    } finally {
      setEnableLoading((prev) => ({ ...prev, [template.id]: false }));
    }
  }

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-lg text-primary text-glow">
            $ infra templates ls
            <span className="ml-1 animate-pulse">_</span>
          </h1>
          <p className="mt-1 text-xs text-muted-foreground">
            {">"} pre-built detection templates for infrastructure monitoring
          </p>
        </div>
        <div className="flex items-center gap-2">
          <Button asChild variant="outline" size="sm">
            <Link href="/infra">{"<"} overview</Link>
          </Button>
          <Button asChild variant="outline" size="sm">
            <Link href="/detections">view detections</Link>
          </Button>
        </div>
      </div>

      {/* Template cards */}
      <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-3">
        {TEMPLATES.map((template) => {
          const busy = enableLoading[template.id] ?? false;
          const enabled = enabledTemplates.has(template.id);

          return (
            <Card
              key={template.id}
              className="flex flex-col transition-colors hover:border-primary/30"
            >
              <CardHeader>
                <div className="flex items-center justify-between">
                  <span
                    className={cn(
                      "font-mono text-sm",
                      categoryColor[template.category] ?? "text-primary",
                    )}
                  >
                    {template.icon}
                  </span>
                  <span
                    className={cn(
                      "text-xs font-mono",
                      severityColor[template.severity] ??
                        "text-muted-foreground",
                    )}
                  >
                    [{template.severity}]
                  </span>
                </div>
                <CardTitle className="mt-2">{template.name}</CardTitle>
                <p className="text-xs text-muted-foreground mt-1">
                  {template.description}
                </p>
              </CardHeader>
              <CardContent className="flex-1 flex flex-col justify-between">
                {/* Features */}
                <div className="space-y-1 mb-4">
                  {template.features.map((feature, i) => (
                    <div key={i} className="flex items-start gap-2 text-xs">
                      <span className="text-primary shrink-0">[+]</span>
                      <span className="text-muted-foreground">{feature}</span>
                    </div>
                  ))}
                </div>

                {/* Enable button */}
                <Button
                  className="w-full"
                  variant={enabled ? "outline" : "default"}
                  disabled={busy || enabled}
                  onClick={() => enableTemplate(template)}
                >
                  {busy
                    ? "> enabling..."
                    : enabled
                      ? "[enabled] view in detections"
                      : "$ enable"}
                </Button>
              </CardContent>
            </Card>
          );
        })}
      </div>

      {/* Info */}
      <div className="text-xs text-muted-foreground space-y-1 border-t border-border pt-4">
        <p>
          {">"} enabling a template creates a detection rule in your detections
          list.
        </p>
        <p>
          {">"} you can customize thresholds and notification channels after
          enabling.
        </p>
        <p>
          {">"} templates require at least one monitored host. add hosts at{" "}
          <Link href="/infra/hosts" className="text-primary hover:underline">
            /infra/hosts
          </Link>
          .
        </p>
      </div>
    </div>
  );
}
